module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output wire valid_out,
    output wire dout
);

reg [3:0] data;
reg valid;
reg [1:0] cnt;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data <= 4'b0;
        valid <= 1'b0;
        cnt <= 2'b0;
    end
    else begin
        if (cnt == 2'd3) begin
            data <= d;
            valid <= 1'b1;
            cnt <= 2'b0;
        end
        else begin
            data <= {data[2:0], data[3]};
            valid <= 1'b0;
            cnt <= cnt + 2'd1;
        end
    end
end

assign dout = data[3];
assign valid_out = valid;

endmodule
